module RefModule(
    A,
    B,
    OPCODE,
    RESET,
    RESULT
);input [31:0] A;
    input [31:0] B;
    input [1:0] OPCODE;
    input RESET;
    output [31:0] RESULT;

    reg [31:0] unused_result;

    always @(*) begin
        case(OPCODE)
            2'b00: unused_result = A + B; // addition
            2'b01: unused_result = A - B; // subtraction
            2'b10: unused_result = A * B; // multiplication
            2'b11: unused_result = A / B; // division
            default: unused_result = 0; // default case
        endcase

        if(RESET) begin
            unused_result = 0; // reset unused_result to 0
        end
    end

    assign RESULT = unused_result;

endmodule
